const response = $input.all()[0].json;
const books = response.books || {};

const artifacts = [
  'notes.md', 'storyboard.md', 'chunks.md', 'chunks-display.md',
  'audio/voiceover.wav', 'output/section-timing.json',
  'output/subtitles.srt', 'output/video.mp4',
  'image-prompts.md', 'metadata.md'
];

const shortNames = artifacts.map(a => a.replace('output/', '').replace('audio/', ''));
const headerCells = shortNames.map(a => `<th style="padding:6px 8px;font-size:12px;white-space:nowrap">${a}</th>`).join('');

const slugs = Object.keys(books).sort();
let rows = '';
let totalBooks = slugs.length;
let completedBooks = 0;

for (const slug of slugs) {
  const fileMap = books[slug] || {};
  let cells = '';
  let allDone = true;
  for (const art of artifacts) {
    const has = fileMap[art] === true;
    if (!has) allDone = false;
    cells += `<td style="text-align:center;color:${has ? '#22c55e' : '#ef4444'}">${has ? '\u2713' : '\u2717'}</td>`;
  }
  if (allDone) completedBooks++;
  rows += `<tr><td style="font-weight:600;padding:6px 12px;white-space:nowrap">${slug}</td>${cells}</tr>`;
}

const html = `<!DOCTYPE html>
<html>
<head><meta charset="utf-8"><title>Bookie Pipeline Status</title></head>
<body style="font-family:system-ui,-apple-system,sans-serif;max-width:1200px;margin:40px auto;padding:0 20px;background:#0f172a;color:#e2e8f0">
  <h1 style="font-size:24px;margin-bottom:8px">Bookie Pipeline Status</h1>
  <p style="color:#94a3b8;margin-bottom:24px">${totalBooks} books | ${completedBooks} complete</p>
  <div style="overflow-x:auto">
    <table style="border-collapse:collapse;width:100%">
      <thead><tr style="background:#1e293b"><th style="padding:6px 12px;text-align:left">Book</th>${headerCells}</tr></thead>
      <tbody>${rows}</tbody>
    </table>
  </div>
  <p style="color:#64748b;font-size:12px;margin-top:24px">Generated at ${new Date().toISOString()}</p>
</body>
</html>`;

return [{ json: { html } }];
